// background.js - Enhanced with CDP engine + Session manager + Event bus
// Patterns from ChatGPT Codex: persistent CDP, tab leasing, event-driven architecture, heartbeat

import { runtime, tabs } from './browser-polyfill.js';
import { sendNative, connectNative, startHeartbeat, stopHeartbeat, checkHeartbeat, getNativeStatus, onNativeStatus, startReconnectAlarm, stopReconnectAlarm } from './native-client.js';
import { fetchGatewayModels } from './provider-gateway.js';
import { parseStructuredBlocks } from './block-parser.js';
import { getCdpEngine } from './cdp-engine.js';
import { getSessionManager } from './session-manager.js';
import { getEventBus } from './event-bus.js';
import { getModelSelector } from './model-selector.js';

// Initialize engines
const cdp = getCdpEngine();
const sessions = getSessionManager();
const bus = getEventBus();
const modelSelector = getModelSelector();

// ====== Initialization ======
async function initialize() {
  // Load persisted sessions
  await sessions.loadFromStorage();

  // Register RPC handlers
  bus.register("ping", () => ({ pong: true, timestamp: Date.now() }));
  bus.register("status", () => ({
    native: getNativeStatus(),
    cdp: cdp.getActiveSessions().size,
    sessions: sessions.getActiveSessions().size,
    eventBus: bus.getStats()
  }));

  // Model selection RPC (agent-driven, not user-picked)
  bus.register("model.select", async ({ goal, constraints }) => {
    return modelSelector.selectModel(goal, { constraints });
  });
  bus.register("model.analyze", ({ goal }) => modelSelector.analyzeTask(goal));

  // Set up alarm handlers
  setupAlarms();

  // Start heartbeat
  await startHeartbeat();

  // Connect native host
  connectNative().catch(() => {
    // Will retry via alarm
  });
}

// ====== Alarm handlers (pattern from Codex) ======
function setupAlarms() {
  runtime.onAlarm?.addListener(async (alarm) => {
    switch (alarm.name) {
      case "native-host-heartbeat":
        await checkHeartbeat();
        break;
      case "native-host-reconnect":
        if (!getNativeStatus().connected) {
          connectNative().catch(() => {});
        }
        break;
      default:
        break;
    }
  });
}

// ====== Message Router ======
runtime.onMessage.addListener((message, sender, sendResponse) => {
  const { type, payload, ...options } = message || {};

  if (!type || typeof type !== 'string') {
    return sendResponse({ ok: false, error: { message: 'Invalid message type' } });
  }

  // RPC-style messages
  if (type.startsWith('rpc.')) {
    handleRpc(type, payload, sender)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({
        ok: false,
        error: { message: error.message, code: error.code, retryable: Boolean(error.retryable) }
      }));
    return true;
  }

  // CDP actions
  if (type.startsWith('cdp.')) {
    handleCdpAction(type, payload, sender)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({
        ok: false,
        error: { message: error.message, code: error.code, retryable: Boolean(error.retryable) }
      }));
    return true;
  }

  // Native host actions
  if (type.startsWith('native.')) {
    const nativeType = type.slice('native.'.length);
    sendNative(nativeType, payload, options)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({
        ok: false,
        error: {
          message: error.message,
          code: error.code,
          retryable: Boolean(error.retryable),
          details: error.details
        }
      }));
    return true;
  }

  // Provider model fetch
  if (type === 'provider.fetchModels') {
    fetchGatewayModels()
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({ ok: false, error: { message: error.message } }));
    return true;
  }

  // ChatGPT web messages
  if (type.startsWith('chatgpt.')) {
    handleChatGptMessage(type, payload, options, sender)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({ ok: false, error: { message: error.message } }));
    return true;
  }

  // MiniMax Agent web messages
  if (type.startsWith('minimax-agent.')) {
    handleMinimaxAgentMessage(type, payload, options, sender)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({ ok: false, error: { message: error.message } }));
    return true;
  }

  // Session management
  if (type.startsWith('session.')) {
    handleSessionMessage(type, payload)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({ ok: false, error: { message: error.message } }));
    return true;
  }

  // AI tabs discovery
  if (type === 'ai.tabs.discover') {
    handleAiTabsDiscover(payload)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({ ok: false, error: { message: error.message } }));
    return true;
  }

  // Browser actions
  if (type.startsWith('browser.')) {
    handleBrowserAction(type, payload)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({
        ok: false,
        error: { message: error.message, code: error.code, retryable: Boolean(error.retryable) }
      }));
    return true;
  }

  // Chat/task actions
  if (type.startsWith('chat.') || type.startsWith('task.')) {
    const nativeType = type.startsWith('chat.') ? type.slice('chat.'.length) : type;
    sendNative(nativeType, payload, options)
      .then((result) => sendResponse({ ok: true, result }))
      .catch((error) => sendResponse({
        ok: false,
        error: {
          message: error.message,
          code: error.code,
          retryable: Boolean(error.retryable),
          details: error.details
        }
      }));
    return true;
  }

  return sendResponse({ ok: false, error: { message: `Unknown message type: ${type}` } });
});

// ====== RPC Handler ======
async function handleRpc(type, payload, sender) {
  const method = type.slice('rpc.'.length);
  return bus.call(method, payload);
}

// ====== CDP Action Handler ======
async function handleCdpAction(type, payload = {}, sender) {
  const action = type.slice('cdp.'.length);
  const tabId = payload.tabId || sender?.tab?.id;

  switch (action) {
    case 'attach':
      return cdp.attach(tabId, payload);
    case 'detach':
      return cdp.detach(tabId);
    case 'send':
      return cdp.send(tabId, payload.method, payload.params, payload.options);
    case 'navigate':
      return cdp.navigate(tabId, payload.url);
    case 'click':
      return cdp.click(tabId, payload.x, payload.y, payload);
    case 'type':
      return cdp.type(tabId, payload.text);
    case 'evaluate':
      return { value: await cdp.evaluate(tabId, payload.expression, payload) };
    case 'screenshot':
      return cdp.screenshot(tabId, payload);
    case 'html':
      return { html: await cdp.getOuterHTML(tabId, payload) };
    case 'console_logs':
      return { logs: await cdp.getConsoleLogs(tabId, payload) };
    case 'network_logs':
      return { logs: await cdp.getNetworkLogs(tabId, payload) };
    case 'wait_load':
      return cdp.waitForLoad(tabId, payload);
    case 'sessions':
      return cdpSessionsInfo();
    default:
      throw new Error(`Unknown CDP action: ${action}`);
  }
}

function cdpSessionsInfo() {
  const active = cdp.getActiveSessions();
  return {
    sessions: Array.from(active.entries()).map(([tabId, session]) => ({
      tabId,
      refCount: session.refCount,
      attachedAt: session.attachedAt,
      enabledDomains: [...session.enabledDomains]
    }))
  };
}

// ====== Session Message Handler ======
async function handleSessionMessage(type, payload = {}) {
  const action = type.slice('session.'.length);
  const { sessionId, tabId, turnId, origin } = payload;

  switch (action) {
    case 'create':
      return sessions.createSession(sessionId, { turnId, origin });
    case 'end':
      return sessions.endSession(sessionId);
    case 'claim':
      return sessions.claimTab(sessionId, tabId, { turnId, origin });
    case 'release':
      return sessions.releaseTab(sessionId, tabId);
    case 'handoff':
      return sessions.handoffTab(sessionId, tabId, { turnId });
    case 'resume':
      return sessions.resumeHandoff(sessionId, tabId, { turnId });
    case 'get':
      return sessions.getSessionTabs(sessionId);
    case 'lease':
      return sessions.getTabLease(tabId);
    case 'list':
      return sessions.getActiveSessions();
    default:
      throw new Error(`Unknown session action: ${action}`);
  }
}

// ====== AI Tabs Discovery ======
async function handleAiTabsDiscover(payload = {}) {
  const patterns = [
    /chatgpt\.com/,
    /chat\.openai\.com/,
    /agent\.minimax\.io/,
    /www\.minimax\.io/,
    /minimax\.io/,
    /claude\.ai/,
    /anthropic\.com/,
    /gemini\.google/,
    /poe\.com/,
    /pi\.ai/,
    /you\.com/,
    /bing\.com/,
    /copilot\.microsoft\.com/
  ];

  const allTabs = await tabs.query({});
  return {
    tabs: allTabs.filter(tab => patterns.some(p => p.test(tab.url || ""))).map(tab => ({
      id: tab.id,
      url: tab.url,
      title: tab.title,
      active: tab.active
    }))
  };
}

// ====== Browser Action Handler ======
async function handleBrowserAction(type, payload = {}) {
  const { runBrowserAction } = await import('./browser-agent.js');
  return runBrowserAction({ action: type, ...payload });
}

// ====== ChatGPT Message Handler ======
async function handleChatGptMessage(type, payload, options, sender) {
  if (type === 'chatgpt.blocks') {
    return handleChatGptBlocks(payload, sender);
  }

  const tabId = sender.tab?.id;
  if (!tabId) {
    throw new Error('No sender tab for chatgpt message');
  }

  const strippedType = type.replace('chatgpt.', '');
  try {
    return await tabs.sendMessage(tabId, { type: strippedType, payload });
  } catch {
    const chatTabs = await tabs.query({ url: ['https://chatgpt.com/*', 'https://chat.openai.com/*'] });
    if (!chatTabs.length) throw new Error('No ChatGPT tab found');
    return await tabs.sendMessage(chatTabs[0].id, { type: strippedType, payload });
  }
}

// ====== MiniMax Agent Message Handler ======
async function handleMinimaxAgentMessage(type, payload, options, sender) {
  const tabId = sender.tab?.id;

  if (type === 'minimax-agent.ask') {
    if (!tabId) {
      throw new Error('No sender tab for minimax-agent message');
    }
    return tabs.sendMessage(tabId, { type: 'minimax.ask', payload });
  }

  if (type === 'minimax-agent.status') {
    if (!tabId) {
      throw new Error('No sender tab for minimax-agent message');
    }
    return tabs.sendMessage(tabId, { type: 'minimax.status', payload });
  }

  if (type === 'minimax-agent.session.capture') {
    if (!tabId) {
      throw new Error('No sender tab for minimax-agent message');
    }
    return tabs.sendMessage(tabId, { type: 'minimax.session.capture', payload });
  }

  if (type === 'minimax-agent.session.tokens') {
    if (!tabId) {
      throw new Error('No sender tab for minimax-agent message');
    }
    return tabs.sendMessage(tabId, { type: 'minimax.session.tokens', payload });
  }

  // Handle provider bridge chat requests
  if (type === 'minimax-agent.chat') {
    const minimaxTabs = await tabs.query({ url: ['https://agent.minimax.io/*', 'https://www.minimax.io/*', 'https://minimax.io/*'] });
    if (!minimaxTabs.length) {
      throw new Error('No MiniMax Agent tab found. Please open https://agent.minimax.io');
    }
    return tabs.sendMessage(minimaxTabs[0].id, { type: 'minimax.chat', payload });
  }

  // Fallback: try to find any MiniMax Agent tab
  const minimaxTabs = await tabs.query({ url: ['https://agent.minimax.io/*', 'https://www.minimax.io/*', 'https://minimax.io/*'] });
  if (!minimaxTabs.length) {
    throw new Error('No MiniMax Agent tab found. Please open https://agent.minimax.io');
  }

  const strippedType = type.replace('minimax-agent.', '');
  return tabs.sendMessage(minimaxTabs[0].id, { type: strippedType, payload });
}

async function handleChatGptBlocks(payload, sender) {
  const { text, sendResultBack } = payload || {};
  if (!text || typeof text !== 'string') return { executed: false, reason: 'no text' };

  const blocks = parseStructuredBlocks(text);
  if (!blocks.length) return { executed: false, reason: 'no blocks found' };

  const results = [];
  for (const block of blocks) {
    try {
      let result;
      if (block.type === 'tool_call') {
        result = await sendNative('tool_call', block.payload);
      } else if (block.type === 'payload_load') {
        result = await sendNative('payload_load', block.payload);
      } else if (block.type.startsWith('filesystem_')) {
        result = await sendNative(block.type, block.payload);
      } else if (block.type === 'agent_action') {
        result = await sendNative('agent_action', block.payload);
      } else if (block.type === 'task_result') {
        result = await sendNative('task_result', block.payload);
      } else if (block.type === 'task_event') {
        result = await sendNative('task_event', block.payload);
      } else {
        result = { error: { message: `Unsupported block type: ${block.type}` } };
      }
      results.push({ blockId: block.blockId, ok: true, result });
    } catch (error) {
      results.push({
        blockId: block.blockId,
        ok: false,
        error: {
          message: error.message,
          code: error.code,
          retryable: Boolean(error.retryable),
          details: error.details
        }
      });
    }
  }

  if (sendResultBack) {
    const fallbackTabId = sender.tab?.id || (await tabs.query({ url: ['https://chatgpt.com/*', 'https://chat.openai.com/*'] }))[0]?.id;
    if (fallbackTabId) {
      try {
        await tabs.sendMessage(fallbackTabId, { type: 'chatgpt.blocks_result', payload: { results } });
      } catch { /* content script may not be listening */ }
    }
  }

  return { executed: true, results, count: results.length };
}

// ====== Start ======
initialize().catch(console.error);

{
  "name": "tiiextension",
  "version": "1.3.0",
  "private": true,
  "type": "module",
  "description": "Tiiextension: Chrome/Edge MV3 extension plus native host, MCP bridge, and tunnel-ready GPT control runtime.",
  "scripts": {
    "test": "node --test tests/*.test.mjs",
    "check": "node scripts/check-syntax.mjs",
    "static-check": "node scripts/static-ui-check.mjs",
    "package": "node scripts/package-release.mjs",
    "package:firefox": "node scripts/package-release.mjs --firefox",
    "package:dry-run": "node scripts/package-release.mjs --dry-run",
    "doctor": "node native-host/bin/agent-cli.js doctor",
    "orchestrator:up": "node native-host/bin/agent-cli.js up",
    "orchestrator:down": "node native-host/bin/agent-cli.js down",
    "orchestrator:status": "node native-host/bin/agent-cli.js status"
  },
  "engines": {
    "node": ">=18"
  },
  "devDependencies": {
    "@playwright/test": "^1.61.1"
  }
}

import { runtime } from './browser-polyfill.js';
import { sendNative } from './native-client.js';
import { initPairingUI } from './pairing.js';

let elements = {};

const state = {
  activePanel: "agent",
  taskId: null,
  eventCursor: 0,
  roots: [],
  selectedRoot: null,
  selectedPath: null,
  transactionId: null,
  running: false
};

function getElements() {
  return {
    "provider-status": document.getElementById("provider-status"),
    "native-status": document.getElementById("native-status"),
    "goal": document.getElementById("goal"),
    "run-goal": document.getElementById("run-goal"),
    "cancel-task": document.getElementById("cancel-task"),
    "task-state": document.getElementById("task-state"),
    "task-summary": document.getElementById("task-summary"),
    "agent-messages": document.getElementById("agent-messages"),
    "workspace-select": document.getElementById("workspace-select"),
    "file-tree": document.getElementById("file-tree"),
    "file-preview": document.getElementById("file-preview"),
    "preview-title": document.getElementById("preview-title"),
    "search-input": document.getElementById("search-input"),
    "search-kind": document.getElementById("search-kind"),
    "search-results": document.getElementById("search-results"),
    "transaction-summary": document.getElementById("transaction-summary"),
    "diff-view": document.getElementById("diff-view"),
    "snapshot-list": document.getElementById("snapshot-list"),
    "task-timeline": document.getElementById("task-timeline"),
    "diagnostic-log": document.getElementById("diagnostic-log"),
    "direct-tool": document.getElementById("direct-tool"),
    "direct-args": document.getElementById("direct-args"),
    "clear-chat": document.getElementById("clear-chat"),
    "model-from-cookie": document.getElementById("model-from-cookie"),
    "model-effort": document.getElementById("model-effort"),
    "cookie-status": document.getElementById("cookie-status"),
    "refresh-model-cookie": document.getElementById("refresh-model-cookie")
  };
}

document.addEventListener("DOMContentLoaded", () => {
  elements = getElements();
  bindEvents();
  initialize().catch(console.error);
});

function bindEvents() {
  // Bind panel navigation buttons
  const panelButtons = getElements();
  for (const button of document.querySelectorAll("[data-panel]")) {
    button.addEventListener("click", () => showPanel(button.dataset.panel));
  }

  // Bind other elements after elements is populated
  document.getElementById("refresh-all").addEventListener("click", refreshAll);
  document.getElementById("refresh-tree").addEventListener("click", loadTree);
  document.getElementById("refresh-changes").addEventListener("click", refreshChanges);
  document.getElementById("refresh-activity").addEventListener("click", refreshActivity);

  if (elements["run-goal"]) {
    elements["run-goal"].addEventListener("click", runGoal);
  }
  if (elements["cancel-task"]) {
    elements["cancel-task"].addEventListener("click", cancelTask);
  }
  if (elements["clear-chat"]) {
    elements["clear-chat"].addEventListener("click", clearChat);
  }
  document.getElementById("run-search").addEventListener("click", runSearch);
  document.getElementById("create-snapshot").addEventListener("click", createSnapshot);
  document.getElementById("run-direct-tool").addEventListener("click", runDirectTool);

  if (elements["refresh-model-cookie"]) {
    elements["refresh-model-cookie"].addEventListener("click", refreshModelFromCookie);
  }
  if (elements["workspace-select"]) {
    elements["workspace-select"].addEventListener("change", () => {
      state.selectedRoot = state.roots.find((root) => root.path === elements["workspace-select"].value) || null;
      loadTree();
    });
  }
  if (elements.goal) {
    elements.goal.addEventListener("keydown", (event) => {
      if (event.key === "Enter" && (event.ctrlKey || event.metaKey)) runGoal();
    });
  }
}

async function initialize() {
  appendDiagnostic("Initializing extension and native runtime...");
  initPairingUI();
  await refreshAll();
  refreshModelFromCookie();
  setInterval(() => {
    if (state.taskId) refreshActivity().catch(() => {});
  }, 1800);
}

async function refreshAll() {
  await Promise.allSettled([
    refreshConnections(), 
    loadWorkspace(), 
    refreshChanges(), 
    refreshActivity()
  ]);
}

// ===== MODEL FROM COOKIE =====
async function refreshModelFromCookie() {
  const modelEl = elements["model-from-cookie"];
  const effortEl = elements["model-effort"];
  const statusEl = elements["cookie-status"];

  if (!modelEl) return;

  modelEl.textContent = "Đang kiểm tra...";
  modelEl.className = "model-badge loading";
  effortEl.textContent = "";
  statusEl.textContent = "";

  try {
    // Send message to content script to get oai-last-model-config cookie
    const response = await call("chatgpt.extract_model", {});

    if (response && response.success && response.model) {
      modelEl.textContent = response.model;
      modelEl.className = "model-badge ready";

      effortEl.textContent = response.effort || "standard";
      effortEl.className = `effort-badge ${response.effort || "standard"}`;

      statusEl.textContent = "✅ Model đọc từ cookie ChatGPT";
      statusEl.className = "cookie-status-text ok";

      appendDiagnostic(`Model extracted: ${response.model} (effort: ${response.effort})`);
    } else {
      modelEl.textContent = "Chưa có model";
      modelEl.className = "model-badge pending";
      statusEl.textContent = "⚠️ Không tìm thấy cookie oai-last-model-config. Hãy mở https://chatgpt.com trước.";
      statusEl.className = "cookie-status-text pending";
    }
  } catch (error) {
    modelEl.textContent = "Lỗi";
    modelEl.className = "model-badge error";
    statusEl.textContent = `❌ ${error.message}`;
    statusEl.className = "cookie-status-text error";
    appendDiagnostic(`Cookie model error: ${error.message}`);
  }
}

// ===== CONNECTION CHECKS =====
async function refreshConnections() {
  try {
    const native = await call("native.connect", {});
    setStatus(elements["native-status"], `Native ${native.hostVersion || "connected"}`, "ok");
  } catch (error) {
    setStatus(elements["native-status"], "Native unavailable", "error");
    appendDiagnostic(error);
  }
  try {
    const provider = await call("chat.status", {});
    setStatus(elements["provider-status"], 
      provider.ready ? `${provider.currentModel || "ChatGPT"} ready` : provider.state || "Provider unavailable", 
      provider.ready ? "ok" : "error");
  } catch (error) {
    setStatus(elements["provider-status"], "Provider unavailable", "error");
    appendDiagnostic(error);
  }
}

// ===== RUN GOAL =====
async function runGoal() {
  const goal = elements.goal.value.trim();
  if (!goal || state.running) return;
  setRunning(true);
  appendMessage("goal", goal);
  elements["task-summary"].classList.remove("empty");
  elements["task-summary"].textContent = "Task submitted. ChatGPT is planning and calling workspace tools…";
  try {
    const started = await call("chat.start", { prompt: goal, mode: "ui", execute: true, maxIterations: 20 });
    state.taskId = started.taskId;
    state.eventCursor = 0;
    elements["cancel-task"].disabled = false;
    elements["task-summary"].textContent = `Task ${state.taskId}\nRunning with ChatGPT Web…`;

    // Poll for task completion
    const job = await waitForJob(state.taskId);
    if (job.status !== "completed") {
      const error = new Error(job.error?.message || `Task ${job.status}`);
      error.code = job.error?.code || `TASK_${job.status.toUpperCase()}`;
      throw error;
    }

    elements["task-state"].textContent = "Completed";
    elements["task-summary"].textContent = `Task ${state.taskId}\nGoal completed\nStatus: ${job.status}`;
    appendMessage("assistant", `Goal "${goal}" completed with status: ${job.status}`);

    await Promise.allSettled([refreshActivity(), refreshChanges(), loadTree()]);
  } catch (error) {
    appendMessage("error", `${error.code || "ERROR"}: ${error.message}`);
    elements["task-state"].textContent = "Failed";
    elements["task-summary"].textContent = error.message;
    appendDiagnostic(error);
  } finally {
    setRunning(false);
  }
}

async function waitForJob(taskId) {
  for (;;) {
    const job = await call("chat.job.get", { taskId });
    await refreshActivity().catch(() => {});
    if (["completed", "failed", "cancelled"].includes(job.status)) return job;
    await new Promise((resolve) => setTimeout(resolve, 900));
  }
}

function showPanel(name) {
  state.activePanel = name;
  document.querySelectorAll("[data-panel]").forEach(btn => {
    btn.classList.toggle("active", btn.dataset.panel === name);
  });
  document.querySelectorAll(".panel-view").forEach(view => {
    view.classList.toggle("active", view.dataset.view === name);
  });
}

function setStatus(element, text, status) {
  element.textContent = text;
  element.className = `status-pill ${status}`;
}

function setRunning(running) {
  state.running = running;
  elements["run-goal"].disabled = running;
  elements["cancel-task"].disabled = !running;
  elements["run-goal"].textContent = running ? "Running..." : "Run with ChatGPT";
}

function appendMessage(type, content) {
  const messageDiv = document.createElement("div");
  messageDiv.className = `message-card message-${type}`;
  messageDiv.textContent = content;
  elements["agent-messages"].appendChild(messageDiv);
  elements["agent-messages"].scrollTop = elements["agent-messages"].scrollHeight;
}

function appendDiagnostic(message) {
  const timestamp = new Date().toLocaleTimeString();
  elements["diagnostic-log"].textContent += `[${timestamp}] ${message}\n`;
  elements["diagnostic-log"].scrollTop = elements["diagnostic-log"].scrollHeight;
}

async function call(type, payload = {}, options = {}) {
  if (type.startsWith('native.')) {
    const nativeType = type.slice('native.'.length);
    return sendNative(nativeType, payload, options);
  }
  const response = await runtime.sendMessage({ type, payload, ...options });
  if (!response?.ok) throw new Error(response?.error?.message || 'Request failed');
  return response.result;
}

async function nativeCall(type, payload = {}) {
  return sendNative(type, payload);
}

async function clearChat() {
  if (confirm("Are you sure you want to clear the chat history?")) {
    elements["agent-messages"].textContent = "";
    elements["task-summary"].classList.add("empty");
    elements["task-summary"].textContent = "No active task.";
    elements["task-state"].textContent = "Idle";
    elements.goal.value = "";
    appendDiagnostic("Chat history cleared");
  }
}

async function loadWorkspace() {
  try {
    const info = await nativeCall("fs.workspace_info", {});
    state.roots = info.roots || [];
    const select = elements["workspace-select"];
    const previous = select.value;
    select.replaceChildren();
    for (const root of state.roots) {
      const option = document.createElement("option");
      option.value = root.path;
      option.textContent = `${root.name || root.id} ${root.read_only ? "read-only" : "read/write"}`;
      select.append(option);
    }
    state.selectedRoot = state.roots.find((root) => root.path === previous) || state.roots[0] || null;
    if (state.selectedRoot) select.value = state.selectedRoot.path;
    await loadTree();
  } catch (error) {
    elements["file-tree"].textContent = `Workspace unavailable: ${error.message}`;
    appendDiagnostic(error);
  }
}

async function loadTree() {
  if (!state.selectedRoot) return;
  elements["file-tree"].textContent = "Loading tree...";
  try {
    const result = await nativeCall("fs.tree", { path: state.selectedRoot.path, depth: 5, maxEntries: 5000 });
    elements["file-tree"].replaceChildren(renderTree(result.tree || [], state.selectedRoot.path));
    if (result.truncated) appendDiagnostic("File tree was truncated by the configured entry limit.");
  } catch (error) {
    elements["file-tree"].textContent = error.message;
    appendDiagnostic(error);
  }
}

function renderTree(items, parentPath) {
  const fragment = document.createDocumentFragment();
  for (const item of items) {
    const node = document.createElement("div");
    node.className = "file-item";
    node.dataset.type = item.type;
    node.dataset.path = joinPath(parentPath, item.name);

    const icon = document.createElement("span");
    icon.className = "file-icon";
    icon.textContent = item.type === "directory" ? "📁" : item.type === "link" ? "🔗" : getFileIcon(item.name);
    node.appendChild(icon);

    const name = document.createElement("span");
    name.className = "file-name";
    name.textContent = item.name;
    node.appendChild(name);

    if (item.type === "file") {
      const size = document.createElement("span");
      size.className = "file-size";
      size.textContent = formatFileSize(item.size || 0);
      node.appendChild(size);

      node.addEventListener("click", () => previewFile(node.dataset.path));
    } else if (item.type === "directory") {
      const children = document.createElement("div");
      children.className = "file-children";
      if (item.children?.length) {
        children.append(renderTree(item.children, node.dataset.path));
      }
      node.appendChild(children);

      node.addEventListener("click", (e) => {
        e.stopPropagation();
        const children = node.querySelector(".file-children");
        if (children) {
          children.style.display = children.style.display === "none" ? "block" : "none";
          node.querySelector(".file-icon").textContent =
            children.style.display === "none" ? "📁" : "📂";
        }
      });

      const childrenEl = node.querySelector(".file-children");
      if (childrenEl) childrenEl.style.display = "none";
    }

    fragment.appendChild(node);
  }
  return fragment;
}

function getFileIcon(filename) {
  const ext = filename.split('.').pop().toLowerCase();
  switch (ext) {
    case 'js': case 'ts': return '📝';
    case 'html': case 'htm': return '🌐';
    case 'css': return '🎨';
    case 'json': return '📋';
    case 'md': case 'markdown': return '📄';
    case 'png': case 'jpg': case 'jpeg': case 'gif': case 'svg': return '🖼️';
    case 'pdf': return '📕';
    case 'zip': case 'rar': case '7z': return '📦';
    default: return '📄';
  }
}

function formatFileSize(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${sizes[i]} ${bytes / Math.pow(k, i) > 1024 ? Math.round(bytes / Math.pow(k, i)) : bytes}`;
}

function joinPath(...parts) {
  return parts.join('/').replace(/\/+/g, '/');
}

async function previewFile(path) {
  try {
    const result = await nativeCall("fs.read", { path, maxBytes: 1024 * 1024 });
    const preview = document.querySelector("#file-preview");
    const title = document.querySelector("#preview-title");
    if (preview) {
      preview.textContent = result.content || result;
      preview.className = "file-preview-content";
    }
    if (title) title.textContent = path;
  } catch (error) {
    appendDiagnostic(`Preview failed: ${error.message}`);
  }
}

async function refreshActivity() {
  const list = elements["task-timeline"];
  if (!list) return;
  try {
    const result = await nativeCall("task.list", { limit: 50 });
    list.replaceChildren();
    for (const task of result.tasks || []) {
      const item = document.createElement("div");
      item.className = "activity-item";
      item.textContent = `${task.task_id || task.id}: ${task.status || 'running'}`;
      list.appendChild(item);
    }
  } catch (error) {
    appendDiagnostic(`refreshActivity failed: ${error.message}`);
  }
}

async function refreshChanges() {
  const diffView = document.getElementById("diff-view");
  if (!diffView) return;
  try {
    const result = await nativeCall("git.status", { path: state.selectedRoot?.path || "." });
    diffView.textContent = JSON.stringify(result, null, 2);
  } catch (error) {
    appendDiagnostic(`refreshChanges failed: ${error.message}`);
  }
}

async function runSearch() {
  const input = elements["search-input"];
  const kind = elements["search-kind"];
  const results = elements["search-results"];
  if (!input || !results) return;

  const query = input.value.trim();
  if (!query) return;

  results.textContent = "Searching...";
  try {
    const tool = kind?.value === "glob" ? "fs.search_glob" : "fs.search_text";
    const result = await nativeCall(tool, {
      path: state.selectedRoot?.path || ".",
      [kind?.value === "glob" ? "pattern" : "query"]: query
    });
    results.textContent = JSON.stringify(result, null, 2);
  } catch (error) {
    results.textContent = `Search failed: ${error.message}`;
    appendDiagnostic(error);
  }
}

async function createSnapshot() {
  if (!state.selectedRoot) {
    appendDiagnostic("No workspace selected");
    return;
  }
  try {
    const result = await nativeCall("snapshot.create", { path: state.selectedRoot.path });
    appendDiagnostic(`Snapshot created: ${result.snapshot_id}`);
    await loadTree();
  } catch (error) {
    appendDiagnostic(`createSnapshot failed: ${error.message}`);
  }
}

async function runDirectTool() {
  const tool = elements["direct-tool"]?.value;
  const args = elements["direct-args"]?.value;
  if (!tool) {
    appendDiagnostic("Tool name required");
    return;
  }
  try {
    const parsedArgs = args ? JSON.parse(args) : {};
    const result = await call(tool, parsedArgs);
    appendDiagnostic(`Tool result: ${JSON.stringify(result)}`);
  } catch (error) {
    appendDiagnostic(`runDirectTool failed: ${error.message}`);
  }
}

function formatExecution(item) {
  const status = item.ok ? "✓" : "✗";
  const tool = item.tool || item.type;
  const result = item.result ? JSON.stringify(item.result).slice(0, 100) : "";
  return `${status} ${tool}: ${result}`;
}
